这里提供一个增强版HTML解析方案，可以智能识别微信文章的标题层级并保持内容结构：

```python
from bs4 import BeautifulSoup, Tag
import re

def wechat_parser(html):
    soup = BeautifulSoup(html, 'lxml')

    # 提取核心内容区域
    content_div = soup.find('div', id='js_content') or soup.body

    # 智能标题识别规则
    TITLE_RULES = [
        {'level': 1, 'patterns': [r'^第[一二三四五六七八九十]+章', r'^[ⅠⅡⅢⅣⅤ]+', r'^[0-9]{1,2}\. ']},
        {'level': 2, 'patterns': [r'^第[0-9]+节', r'^[一二三四五六七八九十]+、']},
        {'level': 3, 'patterns': [r'^（[0-9]+）', r'^[0-9]{1,2}-[0-9]{1,2}']}
    ]

    # 结构化存储
    structured_content = []
    current_section = {'title': None, 'level': 0, 'content': []}

    def is_title(text):
        for rule in TITLE_RULES:
            for pattern in rule['patterns']:
                if re.search(pattern, text.strip()):
                    return rule['level']
        return 0

    def close_section(level):
        nonlocal current_section
        if current_section['title']:
            structured_content.append(current_section.copy())
            current_section = {'title': None, 'level': level, 'content': []}

    for element in content_div.children:
        if isinstance(element, Tag):
            # 处理标题型标签
            if element.name in ['h1', 'h2', 'h3', 'h4']:
                close_section(int(element.name[1:]))
                current_section['title'] = element.get_text().strip()
                current_section['level'] = int(element.name[1:])

            # 处理微信特定样式标题
            elif 'style' in element.attrs:
                font_size = re.search(r'font-size:(\d+)px', element['style'])
                if font_size:
                    size = int(font_size.group(1))
                    if size >= 20:
                        close_section(1)
                        current_section['title'] = element.get_text().strip()
                        current_section['level'] = 1
                    elif size >= 18:
                        close_section(2)
                        current_section['title'] = element.get_text().strip()
                        current_section['level'] = 2

            # 处理文本段落
            elif element.name == 'p':
                text = element.get_text().strip()
                title_level = is_title(text)

                if title_level > 0:
                    close_section(title_level)
                    current_section['title'] = text
                    current_section['level'] = title_level
                else:
                    if text:  # 过滤空段落
                        current_section['content'].append({
                            'type': 'text',
                            'data': text,
                            'styles': element['style'] if 'style' in element.attrs else None
                        })

            # 处理图片
            elif element.name == 'img':
                current_section['content'].append({
                    'type': 'image',
                    'data': element['data-src'] if 'data-src' in element.attrs else element['src']
                })

            # 处理列表
            elif element.name in ['ul', 'ol']:
                list_items = [li.get_text().strip() for li in element.find_all('li')]
                current_section['content'].append({
                    'type': 'list',
                    'data': list_items,
                    'ordered': element.name == 'ol'
                })

    # 添加最后一个section
    close_section(0)

    return {
        'main_title': soup.title.string.strip() if soup.title else '',
        'sections': structured_content
    }

# 转换为Markdown格式
def to_markdown(structured):
    md = []
    md.append(f"# {structured['main_title']}\n")

    for section in structured['sections']:
        level = min(section['level'] + 1, 6)  # Markdown最多支持6级标题
        md.append(f"{'#' * level} {section['title']}\n")

        for content in section['content']:
            if content['type'] == 'text':
                text = content['data']
                # 保留加粗样式
                if content['styles'] and 'font-weight:700' in content['styles']:
                    text = f"**{text}**"
                md.append(f"{text}\n\n")
            elif content['type'] == 'image':
                md.append(f"![image]({content['data']})\n\n")
            elif content['type'] == 'list':
                prefix = '1.' if content['ordered'] else '-'
                md.append('\n'.join([f"{prefix} {item}" for item in content['data']]))
                md.append('\n\n')

    return '\n'.join(md)

# 使用示例
with open('wechat_article.html', 'r', encoding='utf-8') as f:
    html = f.read()

structured = wechat_parser(html)
markdown_content = to_markdown(structured)

with open('formatted_article.md', 'w', encoding='utf-8') as f:
    f.write(markdown_content)
```

### 功能特性：
1. **智能标题识别**：
   - 自动检测多级标题（支持4种识别模式）
   - 通过正则表达式匹配中文章节标识
   - 解析CSS字体大小判断标题层级

2. **内容结构化**：
   ```json
   {
     "main_title": "文章主标题",
     "sections": [
       {
         "title": "章节标题",
         "level": 2,
         "content": [
           {"type": "text", "data": "段落内容", "styles": "字体样式"},
           {"type": "image", "data": "图片URL"},
           {"type": "list", "data": ["列表项"], "ordered": false}
         ]
       }
     ]
   }
   ```

3. **精准排版保留**：
   - 自动转换加粗文本为 `**加粗**`
   - 保留图片原始链接（自动选择data-src/src）
   - 区分有序/无序列表

